import java.sql.*;

public class SQLInjectionFixed {

    public static void main(String[] args) {
        try {
            // Simulated user input (vulnerable to SQL Injection)
            String userInput = "'; DROP TABLE users; --";

            // Establish database connection
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "username", "password");

            // Create a PreparedStatement with parameterized query
            String query = "SELECT * FROM users WHERE username = ?";
            PreparedStatement preparedStatement = connection.prepareStatement(query);

            // Set user input as a parameter in the PreparedStatement
            preparedStatement.setString(1, userInput);

            // Execute the query using the PreparedStatement
            ResultSet resultSet = preparedStatement.executeQuery();

            // Process the query result (not relevant for this example)

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

